CREATE OR REPLACE FUNCTION fpa_lon_m_obj_type_desc (as_lon_type char,ai_lon_obj char) RETURNS varchar AS $body$
DECLARE

  ls_name varchar(100);

BEGIN
  select  loan_objective_description into STRICT ls_name
  from    sc_lon_m_ucf_loan_obj
  where (loan_type = as_lon_type)
  and (loan_objective_code =ai_lon_obj);
  if trim(both ls_name) = 'ไม่ระบุ' or trim(both ls_name) = '<ไม่ระบุ>' then
     ls_name := 'อื่นๆ';
  end if;

return  trim(both ls_name);
exception when others then CALL spa_dberror('FPA_LON_M_OBJ_TYPE_DESC');return null;
END;
$body$
